void logRequest(http.BaseRequest request) {
  String message = "HTTP Request:\nMethod: ${request.method}\nUrl: ${request.uri}";
  
  if (request is http.MultipartRequest) {
    for (var part in (request as http.MultipartRequest).parts) {
      message += "\nPart Data: ${part.dataToString()}";
    }
  } else if (request is http.FormDataRequest) {
